import numpy as np

def calculate_distance(pos1, pos2, speed):
    return np.linalg.norm(pos1 - pos2) / speed

def calculate_penalty(arrival_time, time_window):
    if arrival_time < time_window[0]:
        return time_window[0] - arrival_time
    elif arrival_time > time_window[1]:
        return arrival_time - time_window[1]
    else:
        return 0

