import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):

    def calculate_time(pos1, pos2, speed):
        distance = np.linalg.norm(pos1 - pos2)
        return distance / speed

    best_node = None
    min_total_time = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_time(cur_truck_pos, customer_pos, truck_speed)

        arrival_time = current_time + travel_time

        if time_windows[i][0] <= arrival_time <= time_windows[i][1]:
            total_time = max(arrival_time, time_windows[i][0]) - current_time + travel_time
        elif arrival_time < time_windows[i][0]:
            total_time = time_windows[i][0] - current_time + travel_time
        else:
            total_time = arrival_time - current_time + time_windows[i][1] - arrival_time

        if total_time < min_total_time:
            min_total_time = total_time
            best_node = i

    return best_node
